UPDATE NOTICE 
SET
      NOTICE_TITLE = #{noticeTitle},
      NOTICE_CONTENT = #{noticeContent}
WHERE 1 = 1
  AND NOTICE_UUID = #{noticeUuid, jdbcType=VARCHAR}
  AND WRITE_ID = #{writeId}

UPDATE NOTICE
SET DEL_YN = 'Y'
WHERE NOTICE_UUID = #{noticeUuid, jdbcType=VARCHAR}

	UPDATE NOTICE_FILE
    SET DEL_YN = 'Y'
    WHERE NOTICE_UUID = #{NOTICE_UUID}
